const {
  Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
  HeadingLevel, AlignmentType, BorderStyle, WidthType, ShadingType,
  LevelFormat, PageNumber, NumberFormat, Header, Footer
} = require('docx');
const fs = require('fs');

const BLUE = "1F4E79";
const LIGHT_BLUE = "D6E4F0";
const MID_BLUE = "2E75B6";
const ACCENT = "E8F4FD";
const GRAY = "595959";
const DARK = "1A1A1A";
const DIVIDER_BLUE = "2E75B6";

const border = { style: BorderStyle.SINGLE, size: 1, color: "CCCCCC" };
const borders = { top: border, bottom: border, left: border, right: border };
const noBorder = { style: BorderStyle.NONE, size: 0, color: "FFFFFF" };
const noBorders = { top: noBorder, bottom: noBorder, left: noBorder, right: noBorder };

function heading1(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_1,
    spacing: { before: 320, after: 120 },
    border: { bottom: { style: BorderStyle.SINGLE, size: 6, color: DIVIDER_BLUE, space: 4 } },
    children: [new TextRun({ text, font: "Arial", size: 28, bold: true, color: BLUE })]
  });
}

function heading2(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_2,
    spacing: { before: 240, after: 100 },
    children: [new TextRun({ text, font: "Arial", size: 24, bold: true, color: MID_BLUE })]
  });
}

function body(text, options = {}) {
  return new Paragraph({
    spacing: { before: 80, after: 80 },
    children: [new TextRun({ text, font: "Arial", size: 22, color: DARK, ...options })]
  });
}

function italic(text) {
  return new Paragraph({
    spacing: { before: 60, after: 60 },
    children: [new TextRun({ text, font: "Arial", size: 20, italics: true, color: GRAY })]
  });
}

function bulletItem(text, isSub = false) {
  return new Paragraph({
    numbering: { reference: isSub ? "sub-bullets" : "bullets", level: 0 },
    spacing: { before: 60, after: 60 },
    children: [new TextRun({ text, font: "Arial", size: isSub ? 20 : 22, color: isSub ? GRAY : DARK })]
  });
}

function spacer(pts = 120) {
  return new Paragraph({ spacing: { before: pts, after: 0 }, children: [new TextRun("")] });
}

function infoBox(label, content) {
  return new Table({
    width: { size: 9360, type: WidthType.DXA },
    columnWidths: [1600, 7760],
    rows: [
      new TableRow({
        children: [
          new TableCell({
            borders,
            width: { size: 1600, type: WidthType.DXA },
            shading: { fill: LIGHT_BLUE, type: ShadingType.CLEAR },
            margins: { top: 100, bottom: 100, left: 120, right: 120 },
            verticalAlign: "center",
            children: [new Paragraph({ children: [new TextRun({ text: label, font: "Arial", size: 20, bold: true, color: BLUE })] })]
          }),
          new TableCell({
            borders,
            width: { size: 7760, type: WidthType.DXA },
            shading: { fill: "F8FBFE", type: ShadingType.CLEAR },
            margins: { top: 100, bottom: 100, left: 160, right: 120 },
            children: [new Paragraph({ children: [new TextRun({ text: content, font: "Arial", size: 20, color: DARK })] })]
          })
        ]
      })
    ]
  });
}

function questionCard(num, question, probes) {
  const rows = [
    new TableRow({
      children: [
        new TableCell({
          borders,
          width: { size: 9360, type: WidthType.DXA },
          shading: { fill: MID_BLUE, type: ShadingType.CLEAR },
          margins: { top: 120, bottom: 120, left: 180, right: 180 },
          children: [new Paragraph({
            children: [
              new TextRun({ text: `Q${num}  `, font: "Arial", size: 22, bold: true, color: "FFFFFF" }),
              new TextRun({ text: question, font: "Arial", size: 22, bold: true, color: "FFFFFF" })
            ]
          })]
        })
      ]
    }),
    new TableRow({
      children: [
        new TableCell({
          borders,
          width: { size: 9360, type: WidthType.DXA },
          shading: { fill: "F4F9FE", type: ShadingType.CLEAR },
          margins: { top: 100, bottom: 120, left: 180, right: 180 },
          children: [
            new Paragraph({ spacing: { before: 40, after: 80 }, children: [new TextRun({ text: "Probing Questions:", font: "Arial", size: 20, bold: true, color: MID_BLUE })] }),
            ...probes.map(p => new Paragraph({
              numbering: { reference: "probe-bullets", level: 0 },
              spacing: { before: 40, after: 40 },
              children: [new TextRun({ text: p, font: "Arial", size: 20, color: GRAY, italics: true })]
            })),
            new Paragraph({ spacing: { before: 100, after: 40 }, children: [new TextRun({ text: "Notes:", font: "Arial", size: 20, bold: true, color: GRAY })] }),
            new Paragraph({ spacing: { before: 0, after: 60 }, children: [new TextRun({ text: "_".repeat(90), font: "Arial", size: 18, color: "CCCCCC" })] }),
            new Paragraph({ spacing: { before: 0, after: 60 }, children: [new TextRun({ text: "_".repeat(90), font: "Arial", size: 18, color: "CCCCCC" })] }),
          ]
        })
      ]
    })
  ];

  return new Table({
    width: { size: 9360, type: WidthType.DXA },
    columnWidths: [9360],
    rows
  });
}

function sectionDivider(title) {
  return new Table({
    width: { size: 9360, type: WidthType.DXA },
    columnWidths: [9360],
    rows: [new TableRow({
      children: [new TableCell({
        borders,
        width: { size: 9360, type: WidthType.DXA },
        shading: { fill: BLUE, type: ShadingType.CLEAR },
        margins: { top: 120, bottom: 120, left: 200, right: 200 },
        children: [new Paragraph({ children: [new TextRun({ text: title, font: "Arial", size: 24, bold: true, color: "FFFFFF" })] })]
      })]
    })]
  });
}

const doc = new Document({
  numbering: {
    config: [
      {
        reference: "bullets",
        levels: [{ level: 0, format: LevelFormat.BULLET, text: "\u2022", alignment: AlignmentType.LEFT,
          style: { paragraph: { indent: { left: 540, hanging: 360 } } } }]
      },
      {
        reference: "sub-bullets",
        levels: [{ level: 0, format: LevelFormat.BULLET, text: "\u25E6", alignment: AlignmentType.LEFT,
          style: { paragraph: { indent: { left: 900, hanging: 360 } } } }]
      },
      {
        reference: "probe-bullets",
        levels: [{ level: 0, format: LevelFormat.BULLET, text: "\u25B8", alignment: AlignmentType.LEFT,
          style: { paragraph: { indent: { left: 540, hanging: 300 } } } }]
      },
      {
        reference: "numbers",
        levels: [{ level: 0, format: LevelFormat.DECIMAL, text: "%1.", alignment: AlignmentType.LEFT,
          style: { paragraph: { indent: { left: 540, hanging: 360 } } } }]
      }
    ]
  },
  styles: {
    default: { document: { run: { font: "Arial", size: 22 } } },
    paragraphStyles: [
      { id: "Heading1", name: "Heading 1", basedOn: "Normal", next: "Normal", quickFormat: true,
        run: { size: 28, bold: true, font: "Arial", color: BLUE },
        paragraph: { spacing: { before: 320, after: 120 }, outlineLevel: 0 } },
      { id: "Heading2", name: "Heading 2", basedOn: "Normal", next: "Normal", quickFormat: true,
        run: { size: 24, bold: true, font: "Arial", color: MID_BLUE },
        paragraph: { spacing: { before: 240, after: 100 }, outlineLevel: 1 } },
    ]
  },
  sections: [{
    properties: {
      page: {
        size: { width: 12240, height: 15840 },
        margin: { top: 1080, right: 1260, bottom: 1080, left: 1260 }
      }
    },
    headers: {
      default: new Header({
        children: [
          new Table({
            width: { size: 9720, type: WidthType.DXA },
            columnWidths: [7200, 2520],
            rows: [new TableRow({
              children: [
                new TableCell({
                  borders: noBorders,
                  width: { size: 7200, type: WidthType.DXA },
                  shading: { fill: "FFFFFF", type: ShadingType.CLEAR },
                  children: [new Paragraph({ children: [new TextRun({ text: "Obsidian Usability Focus Group  \u2014  Moderator Script", font: "Arial", size: 18, color: GRAY })] })]
                }),
                new TableCell({
                  borders: noBorders,
                  width: { size: 2520, type: WidthType.DXA },
                  shading: { fill: "FFFFFF", type: ShadingType.CLEAR },
                  children: [new Paragraph({ alignment: AlignmentType.RIGHT, children: [new TextRun({ text: "CONFIDENTIAL", font: "Arial", size: 16, bold: true, color: MID_BLUE })] })]
                })
              ]
            })],
          }),
          new Paragraph({ border: { bottom: { style: BorderStyle.SINGLE, size: 4, color: MID_BLUE, space: 1 } }, children: [new TextRun("")] })
        ]
      })
    },
    footers: {
      default: new Footer({
        children: [
          new Paragraph({ border: { top: { style: BorderStyle.SINGLE, size: 4, color: "CCCCCC", space: 1 } }, children: [new TextRun("")] }),
          new Paragraph({
            children: [
              new TextRun({ text: "For internal research use only    |    Page ", font: "Arial", size: 16, color: GRAY }),
              new TextRun({ children: [PageNumber.CURRENT], font: "Arial", size: 16, color: GRAY }),
              new TextRun({ text: " of ", font: "Arial", size: 16, color: GRAY }),
              new TextRun({ children: [PageNumber.TOTAL_PAGES], font: "Arial", size: 16, color: GRAY }),
            ]
          })
        ]
      })
    },
    children: [
      // Title Block
      new Table({
        width: { size: 9720, type: WidthType.DXA },
        columnWidths: [9720],
        rows: [new TableRow({
          children: [new TableCell({
            borders,
            width: { size: 9720, type: WidthType.DXA },
            shading: { fill: BLUE, type: ShadingType.CLEAR },
            margins: { top: 280, bottom: 280, left: 280, right: 280 },
            children: [
              new Paragraph({ alignment: AlignmentType.CENTER, children: [new TextRun({ text: "OBSIDIAN USABILITY STUDY", font: "Arial", size: 14, color: "B8D4EC", bold: true })] }),
              new Paragraph({ spacing: { before: 60 }, alignment: AlignmentType.CENTER, children: [new TextRun({ text: "Focus Group Moderator Script", font: "Arial", size: 40, bold: true, color: "FFFFFF" })] }),
              new Paragraph({ spacing: { before: 80 }, alignment: AlignmentType.CENTER, children: [new TextRun({ text: "Discovering Usability & Design Issues  \u2014  20\u201330 Minutes", font: "Arial", size: 22, color: "B8D4EC" })] }),
            ]
          })]
        })]
      }),

      spacer(200),

      // Session Info
      infoBox("Date", "___________________________"),
      spacer(60),
      infoBox("Moderator", "___________________________"),
      spacer(60),
      infoBox("Participants", "3\u20135 users  |  Mixed novice / expert"),
      spacer(60),
      infoBox("Duration", "20\u201330 minutes"),
      spacer(60),
      infoBox("Location / Format", "In-person  \u25A1   Remote  \u25A1   Hybrid  \u25A1"),

      spacer(300),

      // ─── SECTION 1: Participant Recruitment ───────────────────────────────
      sectionDivider("PART 1  \u2014  PARTICIPANT RECRUITMENT GUIDE"),
      spacer(160),

      heading1("Who to Recruit"),
      body("Aim for 3\u20135 participants representing a mix of the profiles below. Diversity in experience level and use case will surface a broader range of usability issues."),
      spacer(100),

      heading2("Novice / New Users"),
      bulletItem("Students (undergraduate or graduate) exploring note-taking tools for the first time"),
      bulletItem("Professionals new to personal knowledge management (PKM) software"),
      bulletItem("People currently using simpler tools (e.g., Apple Notes, Notion, Google Docs) who are curious about Obsidian"),
      bulletItem("Tech-comfortable but not tech-savvy individuals \u2014 comfortable with computers but not developers"),

      spacer(120),
      heading2("Intermediate Users"),
      bulletItem("Knowledge workers, researchers, or writers who have used Obsidian for 1\u20136 months"),
      bulletItem("Academics managing literature notes, citations, or research projects"),
      bulletItem("Professionals in fields like UX, consulting, journalism, or project management"),
      bulletItem("Users who are self-taught but have not explored plugins or advanced features"),

      spacer(120),
      heading2("Expert / Power Users"),
      bulletItem("Developers or engineers who use Obsidian daily and have customized their vault extensively"),
      bulletItem("Users who leverage community plugins (e.g., Dataview, Templater, Kanban)"),
      bulletItem("Content creators, podcasters, or writers managing large knowledge bases"),
      bulletItem("Users who migrated from other PKM tools (e.g., Roam Research, Logseq, Notion)"),

      spacer(120),
      heading2("Screener Criteria"),
      bulletItem("At least one participant who has NEVER used Obsidian (pure novice)"),
      bulletItem("At least one participant who uses Obsidian at least 3\u20135 times per week"),
      bulletItem("Mix of operating systems preferred (macOS, Windows, Linux/mobile)"),
      bulletItem("Avoid UX researchers or UI designers who may bias feedback toward professional critique"),

      spacer(300),

      // ─── SECTION 2: Moderator Prep ────────────────────────────────────────
      sectionDivider("PART 2  \u2014  BEFORE THE SESSION"),
      spacer(160),

      heading1("Moderator Preparation Checklist"),
      bulletItem("Prepare a shared Obsidian vault on a neutral device with sample notes loaded"),
      bulletItem("Ensure screen sharing or screen recording is set up and tested"),
      bulletItem("Have participants sign consent / recording release forms before starting"),
      bulletItem("Brief a note-taker to capture reactions and exact quotes during the session"),
      bulletItem("Silence phones and close irrelevant browser tabs"),
      bulletItem("Remind participants: we are testing the software, not them \u2014 there are no wrong answers"),

      spacer(300),

      // ─── SECTION 3: Opening ───────────────────────────────────────────────
      sectionDivider("PART 3  \u2014  OPENING  (3\u20135 minutes)"),
      spacer(160),

      heading1("Welcome & Introduction"),
      body("Read aloud to participants:", { italics: true, color: GRAY }),
      spacer(80),

      new Table({
        width: { size: 9720, type: WidthType.DXA },
        columnWidths: [9720],
        rows: [new TableRow({
          children: [new TableCell({
            borders,
            width: { size: 9720, type: WidthType.DXA },
            shading: { fill: ACCENT, type: ShadingType.CLEAR },
            margins: { top: 140, bottom: 140, left: 200, right: 200 },
            children: [
              new Paragraph({ spacing: { before: 0, after: 100 }, children: [new TextRun({ text: "\u201CThank you for joining us today. My name is [name] and I\u2019ll be your moderator. We\u2019re conducting a focus group to better understand how people experience using Obsidian \u2014 a note-taking and knowledge management tool.", font: "Arial", size: 21, color: DARK })] }),
              new Paragraph({ spacing: { before: 0, after: 100 }, children: [new TextRun({ text: "There are no right or wrong answers. We want your honest impressions, including anything you find confusing, frustrating, or that just doesn\u2019t work the way you expect. Your feedback will directly inform improvements to the product.", font: "Arial", size: 21, color: DARK })] }),
              new Paragraph({ spacing: { before: 0, after: 0 }, children: [new TextRun({ text: "With your permission, we\u2019ll be [recording/taking notes]. Everything you share is confidential and will only be used for research purposes. Do you have any questions before we begin?\u201D", font: "Arial", size: 21, color: DARK })] }),
            ]
          })]
        })]
      }),

      spacer(200),
      heading2("Quick Warm-Up"),
      body("Go around the room. Ask each participant:"),
      bulletItem("\"Tell us your name and, in one sentence, how you currently take notes or manage information.\""),
      italic("Note: This surfaces familiarity levels and sets a comfortable tone."),

      spacer(300),

      // ─── SECTION 4: Main Questions ────────────────────────────────────────
      sectionDivider("PART 4  \u2014  MAIN QUESTIONS  (15\u201320 minutes)"),
      spacer(160),

      body("Allow 2\u20133 minutes per question. Use probing questions to draw out depth. Encourage all participants to respond, not just the most vocal."),
      spacer(160),

      questionCard(1,
        "What were your first impressions when you opened Obsidian for the first time?",
        [
          "What did you notice first \u2014 visually or functionally?",
          "Was there anything that confused or surprised you right away?",
          "How did it compare to tools you\u2019ve used before?",
          "Did you feel like you knew what to do next, or did you feel lost?"
        ]
      ),
      spacer(160),

      questionCard(2,
        "Walk us through how you typically create and organize notes in Obsidian. What does that process look like?",
        [
          "How do you decide where a note goes or what to name it?",
          "Have you ever struggled to find a note you created earlier? What happened?",
          "What organizational features do you actually use versus ignore?",
          "Is there anything about the folder or file structure that feels unnatural?"
        ]
      ),
      spacer(160),

      questionCard(3,
        "What features or parts of the interface do you find most confusing or difficult to use?",
        [
          "Can you give a specific example of a time you got stuck?",
          "How did you eventually figure it out \u2014 trial and error, help docs, someone else?",
          "Are there features you\u2019ve given up on trying to use? Why?",
          "Does anything feel like it requires too many steps to accomplish?"
        ]
      ),
      spacer(160),

      questionCard(4,
        "How do you feel about the visual design and layout of Obsidian?",
        [
          "Is there anything that looks cluttered or overwhelming?",
          "Are there important features or buttons you have trouble finding?",
          "How does it feel to use in a dark environment versus bright light?",
          "Does the interface feel consistent, or do some areas feel out of place?"
        ]
      ),
      spacer(160),

      questionCard(5,
        "How has your experience with Obsidian changed over time \u2014 or what do you think it would take to feel truly comfortable using it?",
        [
          "What was the biggest hurdle you had to get over when learning Obsidian?",
          "Was there a moment where it finally \u2018clicked\u2019? What made that happen?",
          "For those newer to it: what\u2019s stopping you from using it more?",
          "What would have made the learning curve easier?"
        ]
      ),
      spacer(160),

      questionCard(6,
        "If you could change one thing about how Obsidian works or looks, what would it be?",
        [
          "Is this a cosmetic change or a functional one?",
          "Has this issue ever caused you to lose work or miss something?",
          "Have you found a workaround for it, or do you just live with it?",
          "Would that change make you use Obsidian more \u2014 or differently?"
        ]
      ),
      spacer(160),

      questionCard(7,
        "Compared to other note-taking or productivity tools you\u2019ve used, where does Obsidian fall short \u2014 and where does it clearly win?",
        [
          "What does another tool do better that you wish Obsidian did?",
          "Is there anything Obsidian does that you haven\u2019t seen done as well elsewhere?",
          "What would need to change for Obsidian to become your go-to tool (or stay your go-to tool)?",
          "Would you recommend Obsidian to a friend or colleague? Why or why not?"
        ]
      ),

      spacer(300),

      // ─── SECTION 5: Closing ───────────────────────────────────────────────
      sectionDivider("PART 5  \u2014  CLOSING  (2\u20135 minutes)"),
      spacer(160),

      heading1("Wrap-Up"),
      body("Read aloud:", { italics: true, color: GRAY }),
      spacer(80),

      new Table({
        width: { size: 9720, type: WidthType.DXA },
        columnWidths: [9720],
        rows: [new TableRow({
          children: [new TableCell({
            borders,
            width: { size: 9720, type: WidthType.DXA },
            shading: { fill: ACCENT, type: ShadingType.CLEAR },
            margins: { top: 140, bottom: 140, left: 200, right: 200 },
            children: [
              new Paragraph({ spacing: { before: 0, after: 100 }, children: [new TextRun({ text: "\u201CWe\u2019re almost out of time. Before we wrap up, I want to give everyone a chance to share anything we haven\u2019t covered.", font: "Arial", size: 21, color: DARK })] }),
              new Paragraph({ spacing: { before: 0, after: 0 }, children: [new TextRun({ text: "Is there anything about your experience with Obsidian \u2014 a frustration, a feature request, or a pleasant surprise \u2014 that you feel is important for us to know?\u201D", font: "Arial", size: 21, color: DARK })] }),
            ]
          })]
        })]
      }),

      spacer(160),

      heading2("Final Thank You"),
      bulletItem("Thank participants for their time and honesty"),
      bulletItem("Remind them how their feedback will be used"),
      bulletItem("Distribute any incentives (gift cards, credits, etc.)"),
      bulletItem("Provide contact info in case they think of additional feedback later"),

      spacer(300),

      // ─── SECTION 6: Moderator Notes ───────────────────────────────────────
      sectionDivider("PART 6  \u2014  MODERATOR NOTES PAGE"),
      spacer(160),

      heading1("Post-Session Notes"),
      body("Use this page immediately after the session to capture overall impressions before they fade."),
      spacer(120),

      body("Top 3 usability issues mentioned most frequently:", { bold: true }),
      spacer(60),
      new Paragraph({ spacing: { before: 60, after: 80 }, children: [new TextRun({ text: "1.  ______________________________________________________________________", font: "Arial", size: 20, color: GRAY })] }),
      new Paragraph({ spacing: { before: 60, after: 80 }, children: [new TextRun({ text: "2.  ______________________________________________________________________", font: "Arial", size: 20, color: GRAY })] }),
      new Paragraph({ spacing: { before: 60, after: 80 }, children: [new TextRun({ text: "3.  ______________________________________________________________________", font: "Arial", size: 20, color: GRAY })] }),

      spacer(120),
      body("Standout quotes:", { bold: true }),
      spacer(60),
      new Paragraph({ spacing: { before: 60, after: 80 }, children: [new TextRun({ text: "\u201C_______________________________________________________________________\u201D", font: "Arial", size: 20, color: GRAY, italics: true })] }),
      new Paragraph({ spacing: { before: 60, after: 80 }, children: [new TextRun({ text: "\u201C_______________________________________________________________________\u201D", font: "Arial", size: 20, color: GRAY, italics: true })] }),

      spacer(120),
      body("Unexpected findings / surprises:", { bold: true }),
      spacer(60),
      new Paragraph({ spacing: { before: 60, after: 80 }, children: [new TextRun({ text: "_______________________________________________________________________________", font: "Arial", size: 20, color: GRAY })] }),
      new Paragraph({ spacing: { before: 60, after: 80 }, children: [new TextRun({ text: "_______________________________________________________________________________", font: "Arial", size: 20, color: GRAY })] }),

      spacer(120),
      body("Recommended follow-up actions:", { bold: true }),
      spacer(60),
      new Paragraph({ spacing: { before: 60, after: 80 }, children: [new TextRun({ text: "_______________________________________________________________________________", font: "Arial", size: 20, color: GRAY })] }),
      new Paragraph({ spacing: { before: 60, after: 80 }, children: [new TextRun({ text: "_______________________________________________________________________________", font: "Arial", size: 20, color: GRAY })] }),
    ]
  }]
});

Packer.toBuffer(doc).then(buffer => {
  fs.writeFileSync('/mnt/user-data/outputs/Obsidian_Focus_Group_Script.docx', buffer);
  console.log('Done!');
});

