{"language": "javascript", "code": "const {
  Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
  HeadingLevel, AlignmentType, BorderStyle, WidthType, ShadingType,
  LevelFormat, PageNumber, NumberFormat, Header, Footer
} = require('docx');
const fs = require('fs');

const BLUE = "1F4E79";
const LIGHT_BLUE = "D6E4F0";
const MID_BLUE = "2E75B6";
const ACCENT = "E8F4FD";
const GRAY = "595959";
const DARK = "1A1A1A";
const DIVIDER_BLUE = "2E75B6";

const border = { style: BorderStyle.SINGLE, size: 1, color: "CCCCCC" };
const borders = { top: border, bottom: border, left: border, right: border };
const noBorder = { style: BorderStyle.NONE, size: 0, color: "FFFFFF" };
const noBorders = { top: noBorder, bottom: noBorder, left: noBorder, right: noBorder };

function heading1(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_1,
    spacing: { before: 320, after: 120 },
    border: { bottom: { style: BorderStyle.SINGLE, size: 6, color: DIVIDER_BLUE, space: 4 } },
    children: [new TextRun({ text, font: "Arial", size: 28, bold: true, color: BLUE })]
  });
}

function heading2(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_2,
    spacing: { before: 240, after: 100 },
    children: [new TextRun({ text, font: "Arial", size: 24, bold: true, color: MID_BLUE })]
  });
}

function body(text, options = {}) {
  return new Paragraph({
    spacing: { before: 80, after: 80 },
    children: [new TextRun({ text, font: "Arial", size: 22, color: DARK, ...options })]
  });
}

function italic(text) {
  return new Paragraph({
    spacing: { before: 60, after: 60 },
    children: [new TextRun({ text, font: "Arial", size: 20, italics: true, color: GRAY })]
  });
}

function bulletItem(text, isSub = false) {
  return new Paragraph({
    numbering: { reference: isSub ? "sub-bullets" : "bullets", level: 0 },
    spacing: { before: 60, after: 60 },
    children: [new TextRun({ text, font: "Arial", size: isSub ? 20 : 22, color: isSub ? GRAY : DARK })]
  });
}

function spacer(pts = 120) {
  return new Paragraph({ spacing: { before: pts, after: 0 }, children: [new TextRun("")] });
}

function infoBox(label, content) {
  return new Table({
    width: { size: 9360, type: WidthType.DXA },
    columnWidths: [1600, 7760],
    rows: [
      new TableRow({
        children: [
          new TableCell({
            borders,
            width: { size: 1600, type: WidthType.DXA },
            shading: { fill: LIGHT_BLUE, type: ShadingType.CLEAR },
            margins: { top: 100, bottom: 100, left: 120, right: 120 },
            verticalAlign: "center",
            children: [new Paragraph({ children: [new TextRun({ text: label, font: "Arial", size: 20, bold: true, color: BLUE })] })]
          }),
          new TableCell({
            borders,
            width: { size: 7760, type: WidthType.DXA },
            shading: { fill: "F8FBFE", type: ShadingType.CLEAR },
            margins: { top: 100, bottom: 100, left: 160, right: 120 },
            children: [new Paragraph({ children: [new TextRun({ text: content, font: "Arial", size: 20, color: DARK })] })]
          })
        ]
      })
    ]
  });
}

function questionCard(num, question, probes) {
  const rows = [
    new TableRow({
      children: [
        new TableCell({
          borders,
          width: { size: 9360, type: WidthType.DXA },
          shading: { fill: MID_BLUE, type: ShadingType.CLEAR },
          margins: { top: 120, bottom: 120, left: 180, right: 180 },
          children: [new Paragraph({
            children: [
              new TextRun({ text: `Q${num}  `, font: "Arial", size: 22, bold: true, color: "FFFFFF" }),
              new TextRun({ text: question, font: "Arial", size: 22, bold: true, color: "FFFFFF" })
            ]
          })]
        })
      ]
    }),
    new TableRow({
      children: [
        new TableCell({
          borders,
          width: { size: 9360, type: WidthType.DXA },
          shading: { fill: "F4F9FE", type: ShadingType.CLEAR },
          margins: { top: 100, bottom: 120, left: 180, right: 180 },
          children: [
            new Paragraph({ spacing: { before: 40, after: 80 }, children: [new TextRun({ text: "Probing Questions:", font: "Arial", size: 20, bold: true, color: MID_BLUE })] }),
            ...probes.map(p => new Paragraph({
              numbering: { reference: "probe-bullets", level: 0 },
              spacing: { before: 40, after: 40 },
              children: [new TextRun({ text: p, font: "Arial", size: 20, color: GRAY, italics: true })]
            })),
            new Paragraph({ spacing: { before: 100, after: 40 }, children: [new TextRun({ text: "Notes:", font: "Arial", size: 20, bold: true, color: GRAY })] }),
            new Paragraph({ spacing: { before: 0, after: 60 }, children: [new TextRun({ text: "_".repeat(90), font: "Arial", size: 18, color: "CCCCCC" })] }),
            new Paragraph({ spacing: { before: 0, after: 60 }, children: [new TextRun({ text: "_".repeat(90), font: "Arial", size: 18, color: "CCCCCC" })] }),
          ]
        })
      ]
    })
  ];

  return new Table({
    width: { size: 9360, type: WidthType.DXA },
    columnWidths: [9360],
    rows
  });
}

function sectionDivider(title) {
  return new Table({
    width: { size: 9360, type: WidthType.DXA },
    columnWidths: [9360],
    rows: [new TableRow({
      children: [new TableCell({
        borders,
        width: { size: 9360, type: WidthType.DXA },
        shading: { fill: BLUE, type: ShadingType.CLEAR },
        margins: { top: 120, bottom: 120, left: 200, right: 200 },
        children: [new Paragraph({ children: [new TextRun({ text: title, font: "Arial", size: 24, bold: true, color: "FFFFFF" })] })]
      })]
    })]
  });
}

const doc = new Document({
