  export let selectedPoints = [];

  let brushGroup;
  let width = 500;
  let height = 500;
  let margin = { top: 20, right: 20, bottom: 40, left: 50 };

  $: cleanData = data.filter(d => {
    const x = +d.properties?.[varX];
