    <circle
      cx={xScale(+d.properties[varX])}
      cy={yScale(+d.properties[varY])}
      r="4"
      fill={highlightSet.has(d.properties.country) ? "orange" : "steelblue"}
      opacity="0.6"
    />
  {/each}

  {#each cleanData as d}
    <text
      x={xScale(+d.properties[varX]) + 3}
      y={yScale(+d.properties[varY]) - 3}
      font-size="8px"
      fill="black"
    >
      {d.properties.country}
    </text>
  {/each}

  <!-- brush layer must come last so it sits on top and captures mouse events -->
  <g bind:this={brushGroup}></g>
</svg>
