        variable={selectedVar + '_human'}
        bind:filter={filter2}
        update={updateData}
        title="WVS (125 items)"
      />
    </div>
    <div class="hist">
      <Histogram
        data={data}
        fullData={fullData}
        variable={selectedVar + '_llm'}
        bind:filter={filter3}
        update={updateData}
        title="LLM (125 items)"
      />
    </div>
  </div>
</main>
```

Add `filter3` and update `updateData` in the script:

```js
let filter1 = [];
let filter2 = [];
let filter3 = [];

function updateData() {
  let filtered = fullData.filter(d => {
    const v1ok = filter1.length === 0 ||
      (d.properties[selectedVar] >= filter1[0] && d.properties[selectedVar] <= filter1[1]);
    const v2ok = filter2.length === 0 ||
      (d.properties[selectedVar + '_human'] >= filter2[0] && d.properties[selectedVar + '_human'] <= filter2[1]);
    const v3ok = filter3.length === 0 ||
      (d.properties[selectedVar + '_llm'] >= filter3[0] && d.properties[selectedVar + '_llm'] <= filter3[1]);
    return v1ok && v2ok && v3ok;
  });

  data = filtered;

  if (filter1.length > 0 || filter2.length > 0 || filter3.length > 0) {
    selectedCountries = new Set(
      filtered.filter(d => d.properties.country).map(d => d.properties.country)
    );
  } else {
    selectedCountries = new Set();
  }
}
```

Also reset filters when `selectedVar` changes, otherwise stale filter ranges from a different dimension will incorrectly filter the new one:

```js
$: {
  selectedVar;
  filter1 = [];
  filter2 = [];
  filter3 = [];
  data = [...fullData];
  selectedCountries = new Set();
}
```

