const {
  Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
  ExternalHyperlink, AlignmentType, HeadingLevel, LevelFormat,
  BorderStyle, WidthType, ShadingType
} = require("docx");
const fs = require("fs");

const ACCENT  = "4361EE";
const ACCENT2 = "7209B7";
const TEAL    = "0891B2";
const NAVY    = "1A1A2E";
const MUTED   = "6B7280";
const LIGHT   = "EEF2FF";
const LIGHT2  = "F5F0FF";
const LIGHT3  = "ECFEFF";
const RULE    = "CBD5E1";
const WHITE   = "FFFFFF";

const F = "Microsoft YaHei";  // main CJK font
const FA = "Arial";           // Latin/numbers

const spacer = (pt = 6) => new Paragraph({
  children: [new TextRun("")],
  spacing: { before: 0, after: pt * 20 }
});

const hRule = (color = RULE) => new Paragraph({
  children: [new TextRun("")],
  border: { bottom: { style: BorderStyle.SINGLE, size: 6, color, space: 1 } },
  spacing: { before: 60, after: 60 }
});

const sectionLabel = (text, color = ACCENT) => new Paragraph({
  children: [new TextRun({ text, bold: true, color, size: 19, font: F })],
  spacing: { before: 160, after: 80 },
  border: { bottom: { style: BorderStyle.SINGLE, size: 4, color, space: 2 } }
});

const bodyText = (text) => new Paragraph({
  children: [new TextRun({ text, size: 21, font: F, color: NAVY })],
  spacing: { before: 0, after: 80 },
  alignment: AlignmentType.JUSTIFIED
});

const bullet = (text, color = ACCENT) => new Paragraph({
  numbering: { reference: "bullets", level: 0 },
  children: [new TextRun({ text, size: 20, font: F, color: NAVY })],
  spacing: { before: 40, after: 40 }
});

const linkPara = (label, url, color = ACCENT) => new Paragraph({
  children: [
    new TextRun({ text: label + "  ", bold: true, size: 19, font: F, color: NAVY }),
    new ExternalHyperlink({
      link: url,
      children: [new TextRun({ text: url, color, size: 19, font: FA, underline: { type: "single" } })]
    })
  ],
  spacing: { before: 40, after: 60 }
});

const tagRow = (tags, color = ACCENT, bg = LIGHT) => new Paragraph({
  children: tags.flatMap((tag, i) => [
    new TextRun({ text: `  ${tag}  `, size: 17, font: FA, color, bold: true,
      shading: { type: ShadingType.CLEAR, fill: bg } }),
    ...(i < tags.length - 1 ? [new TextRun({ text: "  ", size: 17 })] : [])
  ]),
  spacing: { before: 40, after: 80 }
});

const callout = (label, text, bg, borderColor) => {
  const b = { style: BorderStyle.SINGLE, size: 1, color: RULE };
  const lb = { style: BorderStyle.SINGLE, size: 18, color: borderColor };
  return new Table({
    width: { size: 9360, type: WidthType.DXA }, columnWidths: [9360],
    rows: [new TableRow({ children: [new TableCell({
      borders: { top: b, bottom: b, right: b, left: lb },
      shading: { type: ShadingType.CLEAR, fill: bg },
      margins: { top: 100, bottom: 100, left: 160, right: 160 },
      width: { size: 9360, type: WidthType.DXA },
      children: [
        new Paragraph({ children: [new TextRun({ text: label, bold: true, size: 19, font: F, color: borderColor })], spacing: { before: 0, after: 40 } }),
        new Paragraph({ children: [new TextRun({ text, size: 20, font: F, color: NAVY, italics: true })], spacing: { before: 0, after: 0 } })
      ]
    })] })]
  });
};

const twoCol = (leftChildren, rightChildren) => {
  const none = { style: BorderStyle.NONE, size: 0, color: WHITE };
  const borders = { top: none, bottom: none, left: none, right: none };
  return new Table({
    width: { size: 9360, type: WidthType.DXA }, columnWidths: [4560, 4800],
    rows: [new TableRow({ children: [
      new TableCell({ borders, width: { size: 4560, type: WidthType.DXA }, margins: { top: 0, bottom: 0, left: 0, right: 160 }, children: leftChildren }),
      new TableCell({ borders, width: { size: 4800, type: WidthType.DXA }, margins: { top: 0, bottom: 0, left: 160, right: 0 }, children: rightChildren })
    ]})]
  });
};

